export const TeamSection = ({
  people,
  title,
}: {
  people: Array<{ name: string; role: string; group: string }>;
  title: string;
}) => {
  const groupedByGroup = people.reduce(
    (acc, member) => {
      if (!acc[member.group]) {
        acc[member.group] = [];
      }
      acc[member.group].push(member);
      return acc;
    },
    {} as Record<string, typeof people>,
  );

  const orderedMembers = Object.entries(groupedByGroup).reduce(
    (acc, [group, members]) => {
      const sortedMembers = members.sort((a, b) =>
        a.name.localeCompare(b.name),
      );
      acc[group] = sortedMembers;
      return acc;
    },
    {} as Record<string, typeof people>,
  );

  return (
    <section className="w-full mt-20 flex flex-col items-start gap-6 md:gap-10">
      <h1 className="text-primary font-semibold text-xl md:text-2xl">
        {title}
      </h1>
      {Object.entries(orderedMembers).map(([group, members]) => (
        <div
          key={group}
          className="flex flex-col items-start gap-3 md:gap-4 w-full"
        >
          <h2 className="text-xl font-semibold text-center text-primary break-words line-clamp-2 self-start">
            {group}
          </h2>
          <div className="grid gap-3 grid-cols-4 max-xl:grid-cols-3 max-md:grid-cols-2 max-sm:grid-cols-1 w-full transition-all">
            {members.map((member) => (
              <div key={member.name} className="w-max px-2 flex gap-1">
                <h2 className="text-sm md:text-base font-semibold text-center text-accent-foreground break-words line-clamp-2">
                  {member.name}
                </h2>
                {member.group === "Coordenação" && (
                  <>
                    <span>-</span>
                    <p className="text-xs sm:text-sm text-primary text-center self-center ml-1">
                      {member.role}
                    </p>
                  </>
                )}
              </div>
            ))}
          </div>
        </div>
      ))}
      <section className="w-full mt-20 flex flex-col items-start gap-6 md:gap-10">
        <h2 className="text-2xl font-bold text-primary">
          Jornada de desenvolvimento
        </h2>
        <Timeline />
        <p className="text-xs">
          Para acompanhar detalhes técnicos sobre cada atualização, consultar
          notas de versão completas e conhecer as melhorias implementadas em
          cada etapa de desenvolvimento da plataforma, acesse a página de
          releases do projeto no GitHub. Lá você encontrará o histórico completo
          de mudanças, correções e novos recursos disponibilizados:{" "}
          <a
            href="https://github.com/Benchmark-CO2/bipc/releases"
            target="_blank"
            rel="noopener noreferrer"
            className="text-primary underline"
          >
            https://github.com/Benchmark-CO2/bipc/releases
          </a>
        </p>
      </section>
    </section>
  );
};
